"use client";

import * as React from "react";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

// =============================================================================
// TYPES
// =============================================================================

interface AlignmentChar {
  /** The character */
  char: string;
  /** Start time in seconds */
  start: number;
  /** End time in seconds */
  end: number;
}

interface TranscriptSegment {
  /** Unique ID for the segment */
  id: string;
  /** Speaker label (e.g., "Agent", "User") */
  speaker?: string;
  /** Text content */
  text: string;
  /** Per-character timing alignment (optional) */
  characters?: AlignmentChar[];
  /** Segment start time in seconds */
  startTime?: number;
  /** Segment end time in seconds */
  endTime?: number;
}

interface TranscriptViewerProps
  extends React.ComponentProps<"div">, VariantProps<typeof transcriptVariants> {
  /** Transcript segments to display */
  segments: TranscriptSegment[];
  /** Current playback time in seconds (for highlighting) */
  currentTime?: number;
  /** Called when the user clicks a word/character to seek */
  onSeek?: (time: number) => void;
  /** Whether to auto-scroll to the current segment. Default: true */
  autoScroll?: boolean;
  /** Whether to show speaker labels. Default: true */
  showSpeakers?: boolean;
  /** Whether to show timestamps. Default: false */
  showTimestamps?: boolean;
}

// =============================================================================
// VARIANTS
// =============================================================================

const transcriptVariants = cva(
  "flex flex-col gap-3 overflow-y-auto rounded-xl border border-border bg-background p-4",
  {
    variants: {
      size: {
        sm: "text-sm gap-2 p-3",
        md: "text-base gap-3 p-4",
        lg: "text-lg gap-4 p-5",
      },
    },
    defaultVariants: {
      size: "md",
    },
  }
);

// =============================================================================
// HELPERS
// =============================================================================

function formatTimestamp(seconds: number): string {
  const mins = Math.floor(seconds / 60);
  const secs = Math.floor(seconds % 60);
  return `${mins}:${secs.toString().padStart(2, "0")}`;
}

// =============================================================================
// HIGHLIGHTED TEXT
// =============================================================================

function HighlightedText({
  characters,
  currentTime,
  onSeek,
}: {
  characters: AlignmentChar[];
  currentTime: number;
  onSeek?: (time: number) => void;
}) {
  return (
    <span>
      {characters.map((char, i) => {
        const isActive = currentTime >= char.start && currentTime < char.end;
        const isPast = currentTime >= char.end;

        return (
          <span
            key={i}
            className={cn(
              "transition-colors duration-100 cursor-pointer",
              isActive && "bg-primary/30 text-primary-foreground rounded-sm",
              isPast && "text-foreground",
              !isPast && !isActive && "text-muted-foreground/60"
            )}
            onClick={() => onSeek?.(char.start)}
            role="button"
            tabIndex={-1}
          >
            {char.char}
          </span>
        );
      })}
    </span>
  );
}

// =============================================================================
// SEGMENT
// =============================================================================

function SegmentRow({
  segment,
  currentTime,
  onSeek,
  showSpeaker,
  showTimestamp,
  isActive,
}: {
  segment: TranscriptSegment;
  currentTime?: number;
  onSeek?: (time: number) => void;
  showSpeaker: boolean;
  showTimestamp: boolean;
  isActive: boolean;
}) {
  const rowRef = React.useRef<HTMLDivElement>(null);

  return (
    <div
      ref={rowRef}
      data-segment-id={segment.id}
      className={cn(
        "rounded-lg px-3 py-2 transition-colors",
        isActive && "bg-accent/50"
      )}
    >
      {/* Speaker + timestamp header */}
      {(showSpeaker || showTimestamp) && (
        <div className="flex items-center gap-2 mb-1">
          {showSpeaker && segment.speaker && (
            <span className="text-xs font-medium text-foreground">
              {segment.speaker}
            </span>
          )}
          {showTimestamp && segment.startTime !== undefined && (
            <span
              className="text-xs text-muted-foreground/60 cursor-pointer hover:text-muted-foreground"
              onClick={() => onSeek?.(segment.startTime!)}
              role="button"
              tabIndex={-1}
            >
              {formatTimestamp(segment.startTime)}
            </span>
          )}
        </div>
      )}

      {/* Text content */}
      <div className="leading-relaxed">
        {segment.characters && currentTime !== undefined ? (
          <HighlightedText
            characters={segment.characters}
            currentTime={currentTime}
            onSeek={onSeek}
          />
        ) : (
          <span
            className={cn(
              "transition-colors",
              isActive ? "text-foreground" : "text-muted-foreground"
            )}
          >
            {segment.text}
          </span>
        )}
      </div>
    </div>
  );
}

// =============================================================================
// COMPONENT
// =============================================================================

function TranscriptViewer({
  segments,
  currentTime,
  onSeek,
  autoScroll = true,
  showSpeakers = true,
  showTimestamps = false,
  size,
  className,
  ...props
}: TranscriptViewerProps) {
  const containerRef = React.useRef<HTMLDivElement>(null);

  // Determine active segment
  const activeSegmentId = React.useMemo(() => {
    if (currentTime === undefined) return null;
    for (let i = segments.length - 1; i >= 0; i--) {
      const seg = segments[i];
      if (
        seg.startTime !== undefined &&
        seg.endTime !== undefined &&
        currentTime >= seg.startTime &&
        currentTime < seg.endTime
      ) {
        return seg.id;
      }
      // Fallback: check character-level timing
      if (seg.characters?.length) {
        const firstChar = seg.characters[0];
        const lastChar = seg.characters[seg.characters.length - 1];
        if (currentTime >= firstChar.start && currentTime < lastChar.end) {
          return seg.id;
        }
      }
    }
    return null;
  }, [segments, currentTime]);

  // Auto-scroll to active segment
  React.useEffect(() => {
    if (!autoScroll || !activeSegmentId || !containerRef.current) return;

    const activeEl = containerRef.current.querySelector(
      `[data-segment-id="${CSS.escape(activeSegmentId)}"]`
    );
    if (activeEl) {
      activeEl.scrollIntoView({ behavior: "smooth", block: "nearest" });
    }
  }, [autoScroll, activeSegmentId]);

  return (
    <div
      ref={containerRef}
      data-slot="transcript-viewer"
      className={cn(transcriptVariants({ size }), className)}
      role="log"
      aria-label="Transcript"
      aria-live="polite"
      {...props}
    >
      {segments.length === 0 && (
        <div className="text-center text-muted-foreground/50 py-8">
          No transcript available
        </div>
      )}
      {segments.map((segment) => (
        <SegmentRow
          key={segment.id}
          segment={segment}
          currentTime={currentTime}
          onSeek={onSeek}
          showSpeaker={showSpeakers}
          showTimestamp={showTimestamps}
          isActive={segment.id === activeSegmentId}
        />
      ))}
    </div>
  );
}

TranscriptViewer.displayName = "TranscriptViewer";

export { TranscriptViewer, transcriptVariants };
export type { TranscriptViewerProps, TranscriptSegment, AlignmentChar };
